// Safe parallel DB access: IDbContextFactory<T>
public class ReportService(IDbContextFactory<AppDbContext> factory)
{
    public async Task<(int orders, int products)> GetCountsAsync()
    {
        await using var ctx1 = await factory.CreateDbContextAsync();
        await using var ctx2 = await factory.CreateDbContextAsync();
        var t1 = ctx1.Orders.CountAsync();
        var t2 = ctx2.Products.CountAsync();
        await Task.WhenAll(t1, t2);
        return (t1.Result, t2.Result);
    }
}

