    {
        builder.OwnsOne(o => o.ShippingAddress, addr =>
        {
            addr.Property(a => a.Street).HasMaxLength(200).IsRequired();
            addr.Property(a => a.City).HasMaxLength(100).IsRequired();
            addr.Property(a => a.PostCode).HasMaxLength(20).IsRequired();
